import React, { useState } from 'react';

function QuestionForm({ onSubmit }) {
  const [answers, setAnswers] = useState(Array(8).fill(''));
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const questions = [
    "¿Por qué estás interesado en este puesto?",
    "¿Qué experiencia previa tienes en roles similares?",
    "¿Cómo manejas situaciones de presión o estrés en el trabajo?",
    "¿Cuál ha sido tu mayor logro profesional y por qué?",
    "¿Qué herramientas o tecnologías dominas que consideras relevantes para este puesto?",
    "¿Cómo manejas el trabajo en equipo y la colaboración?",
    "¿Dónde te ves profesionalmente en cinco años?",
    "¿Qué te motiva a dar lo mejor de ti en un empleo?"
  ];

  const palabrasClave = [
  "desarrollador",           // sobre ti
  "proyecto",                // interés en el puesto
  "éxito",                   // mayor logro
  "resiliencia",             // presión
  "colaboración",            // trabajo en equipo
  "objetivos",               // 5 años
  "habilidades",             // por qué contratarte
  "tecnologías"              // experiencia previa
];

  const handleInputChange = (index, value) => {
    const newAnswers = [...answers];
    newAnswers[index] = value;
    setAnswers(newAnswers);
  };

  const evaluarRespuestas = (answers) => {
    const puntuaciones = answers.map((respuesta, i) => {
      let score = 0;
      const texto = respuesta.toLowerCase();

      if (respuesta.trim().length > 50) score += 1; // buena extensión
      if (palabrasClave[i] && texto.includes(palabrasClave[i])) score += 1; // palabra clave presente

      return {
        pregunta: i + 1,
        texto: respuesta,
        puntaje: score
      };
    });

    const total = puntuaciones.reduce((acc, p) => acc + p.puntaje, 0);
    const resultadoFinal = total >= 12
      ? "✅ APTO para la siguiente fase."
      : "⚠️ Se recomienda una revisión más detallada.";

    let informe = "📊 Evaluación automática:\n\n";
    puntuaciones.forEach(p => {
      informe += `Pregunta ${p.pregunta}: ${p.puntaje}/2\n`;
    });
    informe += `\n➡️ Resultado final: ${resultadoFinal}`;

    return informe;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    if (answers.some(answer => answer.trim() === '')) {
      setError('Por favor, responde todas las preguntas.');
      setLoading(false);
      return;
    }

    try {
      await new Promise(resolve => setTimeout(resolve, 800)); // Simula tiempo de análisis
      const result = evaluarRespuestas(answers);
      onSubmit(result, answers); // ✅ Envía también las respuestas
    } catch (err) {
      console.error('Error al simular análisis', err);
      setError('Hubo un error al procesar las respuestas.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      {questions.map((question, i) => (
        <div key={i} style={{ marginBottom: '10px' }}>
          <label htmlFor={`answer-${i}`}>{question}</label><br />
          <textarea
            id={`answer-${i}`}
            rows={3}
            style={{ width: '100%', padding: '8px' }}
            onChange={(e) => handleInputChange(i, e.target.value)}
            value={answers[i]}
            required
            disabled={loading}
          />
        </div>
      ))}

      <button type="submit" disabled={loading} style={{ padding: '10px 20px' }}>
        {loading ? 'Evaluando...' : 'Enviar respuestas'}
      </button>

      {error && <p style={{ color: 'red' }}>{error}</p>}
    </form>
  );
}

export default QuestionForm;
